import "fmt"

type User struct { Name string }

func main() {
	users := []User{{Name: "Alice"}, {Name: "Bob"}}
	var ptrs []*User

	for _, u := range users {
		ptrs = append(ptrs, &u)
	}

	for _, p := range ptrs {
		fmt.Println(p.Name)
	}
